func solve(n: Int64, edges: Array<Array<Int64>>, k: Int64) -> Int64 {
    let n_int = Int(n)
    let k_int = Int(k)

    var maxW: Int64 = 0
    if !edges.isEmpty {
        maxW = edges.reduce(0) { currentMax, edge in
            return max(currentMax, edge[2])
        }
    }

    let edgeList = edges.map { $0.map { Int($0) } }
    let sortedEdges = edgeList.sorted(by: { $0[2] < $1[2] })

    var low: Int64 = 0
    var high: Int64 = maxW

    while low <= high {
        let mid: Int64 = (low + high) / 2
        var parent = Array(0..<n_int)
        var rank = [Int](repeating: 0, count: n_int)
        var compCount = n_int

        for edge in sortedEdges {
            if Int64(edge[2]) > mid {
                break
            }
            let u = edge[0]
            let v = edge[1]

            var rootU = u
            var pathU = [Int]()
            var cur = u
            while parent[cur] != cur {
                pathU.append(cur)
                cur = parent[cur]
            }
            rootU = cur
            for node in pathU {
                parent[node] = rootU
            }

            var rootV = v
            var pathV = [Int]()
            cur = v
            while parent[cur] != cur {
                pathV.append(cur)
                cur = parent[cur]
            }
            rootV = cur
            for node in pathV {
                parent[node] = rootV
            }

            if rootU == rootV {
                continue
            }

            if rank[rootU] < rank[rootV] {
                parent[rootU] = rootV
            } else if rank[rootU] > rank[rootV] {
                parent[rootV] = rootU
            } else {
                parent[rootV] = rootU
                rank[rootU] += 1
            }
            compCount -= 1
        }

        if compCount <= k_int {
            high = mid - 1
        } else {
            low = mid + 1
        }
    }

    return low
}
```

### Explanation
1. **Binary Search Setup**: The binary search is initialized with `low` set to 0 and `high` set to the maximum edge weight in the graph.
2. **Edge Processing**: The edges are sorted by weight to facilitate early termination during processing. For each candidate `mid`:
   - **Union-Find Initialization**: The DSU structures (`parent` and `rank` arrays) are initialized. Each node starts as its own component.
   - **Component Merging**: For each edge with weight ≤ `mid`, the algorithm merges the connected components of the edge's nodes using path compression and union by rank for efficiency.
3. **Feasibility Check**: After processing all edges up to `mid`, the component count is checked. If it is ≤ `k`, the candidate is feasible, and we adjust the search range to find a smaller possible `mid`. Otherwise, the search continues for a larger `mid`.
4. **Result**: The binary search concludes by returning the smallest feasible `mid`, which represents the minimized maximum cost among all connected components.

This approach efficiently narrows down the solution space using binary search and leverages the DSU data structure to manage and check connected components dynamically, ensuring optimal performance.

