func solve(n: Int64, edges: Array<Array<Int64>>, k: Int64) -> Int64 {
    if n == 0 {
        return 0
    }

    var maxWeight: Int64 = 0
    for edge in edges {
        if edge[2] > maxWeight {
            maxWeight = edge[2]
        }
    }

    var low: Int64 = 0
    var high = maxWeight + 1

    while low < high {
        let mid = (low + high) / 2
        if feasible(n: n, edges: edges, x: mid, k: k) {
            high = mid
        } else {
            low = mid + 1
        }
    }

    return low
}

func feasible(n: Int64, edges: Array<Array<Int64>>, x: Int64, k: Int64) -> Bool {
    var parent = [Int64]()
    for i in 0..<n {
        parent.append(i)
    }
    var rank = [Int](repeating: 0, count: Int(n))

    func find(_ a: Int64) -> Int64 {
        var a = a
        while parent[Int(a)] != a {
            parent[Int(a)] = parent[Int(parent[Int(a)])]
            a = parent[Int(a)]
        }
        return a
    }

    func union(_ a: Int64, _ b: Int64) {
        let rootA = find(a)
        let rootB = find(b)
        if rootA == rootB {
            return
        }
        if rank[Int(rootA)] < rank[Int(rootB)] {
            parent[Int(rootA)] = rootB
        } else if rank[Int(rootA)] > rank[Int(rootB)] {
            parent[Int(rootB)] = rootA
        } else {
            parent[Int(rootB)] = rootA
            rank[Int(rootA)] += 1
        }
    }

    var comp = n
    for edge in edges {
        let w = edge[2]
        if w <= x {
            let u = edge[0]
            let v = edge[1]
            let rootU = find(u)
            let rootV = find(v)
            if rootU != rootV {
                union(u, v)
                comp -= 1
            }
        }
    }

    return comp <= k
}
```

